// 将文档内所有公式及公式编号段落设置为左对齐
var doc = Application.ActiveDocument;
var paragraphs = doc.Paragraphs;
var count = paragraphs.Count || 0;
for (var i = 1; i <= count; i++) {
    var para = paragraphs.Item(i);
    if (!para) continue;
    var text = (para.Range.Text || "").trim();
    if (text.indexOf("=") !== -1 || text.indexOf("式") !== -1 || /^\(\d+\)$/.test(text)) {
        para.Range.ParagraphFormat.Alignment = 0;
    }
}
return { success: true, message: "公式及编号已左对齐" };
